/**
 * @swagger
 * tags:
 *   - name: Admin - Franchise Payouts
 *     description: Administrative tools for monitoring and marking Franchise Repurchase (BV) and 1st Purchase (PV) Payouts as paid.
 *   - name: Franchise - Finances
 *     description: Financial tracking and live Repurchase BV and 1st Purchase PV accumulation metrics for the logged-in Franchise.
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/list:
 *   get:
 *     summary: Get paginated list of generated Franchise Payouts (BV & PV)
 *     description: View all monthly payouts generated by the system for franchises. Shows distinct records for BV (Repurchase) and PV (1st Purchase).
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: query
 *         name: page
 *         schema: { type: integer, default: 1 }
 *       - in: query
 *         name: limit
 *         schema: { type: integer, default: 10 }
 *       - in: query
 *         name: status
 *         schema: { type: string, enum: [pending, paid] }
 *     responses:
 *       200:
 *         description: Payout list fetched successfully
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/live-bv:
 *   get:
 *     summary: View real-time, ongoing BV and PV accumulations for franchises this month
 *     description: Watch BV (Repurchase) and PV (1st Purchase) accumulate live throughout the month before the payout triggers.
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: query
 *         name: hasBvOnly
 *         schema: { type: boolean, default: true }
 *     responses:
 *       200:
 *         description: Live BV/PV states fetched successfully
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/{id}/mark-paid:
 *   patch:
 *     summary: Manually mark a pending Franchise Payout as Paid
 *     description: Updates the status of a specific generated payout to paid. Works identically for both BV and PV payouts.
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: path
 *         name: id
 *         required: true
 *         schema: { type: string }
 *     requestBody:
 *       required: false
 *       content:
 *         application/json:
 *           schema:
 *             type: object
 *             properties:
 *               transactionRef: { type: string, example: "NEFT-12345678" }
 *     responses:
 *       200:
 *         description: Payout marked as paid
 */

/**
 * @swagger
 * /api/v1/franchise/payout/history:
 *   get:
 *     summary: Get personal Franchise Payout history (BV & PV)
 *     description: Returns a list of all successful monthly payouts generated for the logged-in franchise, including payoutType (BV or PV).
 *     tags: [Franchise - Finances]
 *     security:
 *       - bearerAuth: []
 *     responses:
 *       200:
 *         description: History fetched successfully
 */

/**
 * @swagger
 * /api/v1/franchise/payout/live-bv:
 *   get:
 *     summary: Get live real-time metrics of BV and PV processed this month
 *     description: See the live amount of BV and PV accumulated this month and the estimated payouts (10% BV, 40 INR per PV).
 *     tags: [Franchise - Finances]
 *     security:
 *       - bearerAuth: []
 *     responses:
 *       200:
 *         description: Live BV/PV fetched successfully
 */
